using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using verii_metivon_api.Modules.Sales.Domain.Entities;namespace verii_metivon_api.Modules.Sales.Infrastructure.Persistence.Configurations;public sealed class SalesOrderConfiguration:IEntityTypeConfiguration<SalesOrder>{public void Configure(EntityTypeBuilder<SalesOrder>b){b.ToTable("RII_SALES_ORDERS");b.HasIndex(x=>x.OrderNumber).IsUnique();b.Property(x=>x.OrderNumber).HasMaxLength(40).IsRequired();foreach(var p in new[]{nameof(SalesOrder.ExchangeRate),nameof(SalesOrder.Subtotal),nameof(SalesOrder.DiscountTotal),nameof(SalesOrder.TaxTotal),nameof(SalesOrder.GrandTotal)})b.Property(p).HasPrecision(24,8);b.HasOne(x=>x.Customer).WithMany().HasForeignKey(x=>x.CustomerId).OnDelete(DeleteBehavior.Restrict);}}public sealed class SalesOrderLineConfiguration:IEntityTypeConfiguration<SalesOrderLine>{public void Configure(EntityTypeBuilder<SalesOrderLine>b){b.ToTable("RII_SALES_ORDER_LINES");b.HasIndex(x=>new{x.SalesOrderId,x.LineNumber}).IsUnique();foreach(var p in new[]{nameof(SalesOrderLine.OrderedQuantity),nameof(SalesOrderLine.ReservedQuantity),nameof(SalesOrderLine.ShippedQuantity),nameof(SalesOrderLine.UnitPrice),nameof(SalesOrderLine.DiscountAmount),nameof(SalesOrderLine.TaxAmount),nameof(SalesOrderLine.LineTotal)})b.Property(p).HasPrecision(24,8);b.Property(x=>x.DiscountRate).HasPrecision(9,6);b.Property(x=>x.TaxRate).HasPrecision(9,6);b.HasOne(x=>x.SalesOrder).WithMany(x=>x.Lines).HasForeignKey(x=>x.SalesOrderId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class SalesOrderParameterSettingsConfiguration:IEntityTypeConfiguration<SalesOrderParameterSettings>{public void Configure(EntityTypeBuilder<SalesOrderParameterSettings>b){b.ToTable("RII_SALES_ORDER_PARAMETERS",t=>{t.HasCheckConstraint("CK_RII_SALES_ORDER_PARAMETERS_LEAD_TIME","[DefaultShipmentLeadTimeDays] >= 0 AND [DefaultShipmentLeadTimeDays] <= 3650");t.HasCheckConstraint("CK_RII_SALES_ORDER_PARAMETERS_MAX_LINES","[MaximumLinesPerOrder] >= 1 AND [MaximumLinesPerOrder] <= 10000");t.HasCheckConstraint("CK_RII_SALES_ORDER_PARAMETERS_DISCOUNT","[MaximumDiscountPercent] >= 0 AND [MaximumDiscountPercent] <= 100");t.HasCheckConstraint("CK_RII_SALES_ORDER_PARAMETERS_AMOUNTS","[MinimumOrderAmount] >= 0 AND [MaximumOrderAmount] >= 0 AND ([MaximumOrderAmount] = 0 OR [MaximumOrderAmount] >= [MinimumOrderAmount])");});b.HasKey(x=>x.Id);b.HasQueryFilter(x=>!x.IsDeleted);b.HasIndex(x=>new{x.BranchId,x.WarehouseId}).IsUnique().HasFilter("[IsDeleted] = 0");b.Property(x=>x.MaximumDiscountPercent).HasPrecision(9,6);b.Property(x=>x.MinimumOrderAmount).HasPrecision(24,8);b.Property(x=>x.MaximumOrderAmount).HasPrecision(24,8);b.Property(x=>x.RowVersion).IsRowVersion();b.HasOne(x=>x.Branch).WithMany().HasForeignKey(x=>x.BranchId).OnDelete(DeleteBehavior.Restrict);b.HasOne(x=>x.Warehouse).WithMany().HasForeignKey(x=>x.WarehouseId).OnDelete(DeleteBehavior.Restrict);}}
